const mammoth = require('mammoth');

const language = $('Edit Fields').first().json['Language'];
const filePath = language === 'English Only' 
  ? '/home/node/.n8n-files/Akshun-EN.docx'
  : '/home/node/.n8n-files/Akshun-DE.docx';

const result = await mammoth.extractRawText({ path: filePath });

return [{
  json: {
    ...$('Edit Fields').first().json,
    resumeText: result.value,
  }
}];
